// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract HorseAuditRegistry {
    address public owner;

    struct AuditRecord {
        string eventType;
        string eventId;
        bytes32 payloadHash;
        bytes32 previousHash;
        bytes32 chainHash;
        uint256 timestamp;
    }

    AuditRecord[] public records;
    mapping(bytes32 => bool) public exists;

    event AuditStored(uint256 indexed index, string eventType, string eventId, bytes32 chainHash);

    modifier onlyOwner() {
        require(msg.sender == owner, "not owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function storeAudit(
        string calldata eventType,
        string calldata eventId,
        bytes32 payloadHash,
        bytes32 previousHash,
        bytes32 chainHash
    ) external onlyOwner {
        require(!exists[chainHash], "audit exists");
        records.push(AuditRecord(eventType, eventId, payloadHash, previousHash, chainHash, block.timestamp));
        exists[chainHash] = true;
        emit AuditStored(records.length - 1, eventType, eventId, chainHash);
    }

    function totalRecords() external view returns (uint256) {
        return records.length;
    }
}

contracts/LocalFirstWalletRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract LocalFirstWalletRegistry {
    event LocalWalletMovementRegistered(
        bytes32 indexed userHash,
        bytes32 indexed movementId,
        bytes32 previousWalletStateId,
        bytes32 newWalletStateId,
        bytes32 payloadHash,
        bytes32 signatureHash,
        uint256 timestamp
    );

    mapping(bytes32 => bytes32) public latestWalletState;
    mapping(bytes32 => bool) public movementExists;

    function registerMovement(
        bytes32 userHash,
        bytes32 movementId,
        bytes32 previousWalletStateId,
        bytes32 newWalletStateId,
        bytes32 payloadHash,
        bytes32 signatureHash
    ) external {
        require(!movementExists[movementId], "movement already registered");
        bytes32 current = latestWalletState[userHash];
        if (current != bytes32(0)) {
            require(current == previousWalletStateId, "invalid previous wallet state");
        }
        movementExists[movementId] = true;
        latestWalletState[userHash] = newWalletStateId;
        emit LocalWalletMovementRegistered(
            userHash,
            movementId,
            previousWalletStateId,
            newWalletStateId,
            payloadHash,
            signatureHash,
            block.timestamp
        );
    }
}

contracts/WalletStateRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/// @title WalletStateRegistry
/// @notice Registro mínimo para auditar estados rotativos de wallet.
/// El contrato no guarda saldos ni datos personales; solo hashes e IDs públicos.
contract WalletStateRegistry {
    struct WalletMovement {
        string userRef;
        string previousStateId;
        string newStateId;
        string movementId;
        bytes32 payloadHash;
        bytes32 signatureHash;
        uint256 createdAt;
    }

    address public owner;
    uint256 public totalMovements;
    mapping(string => WalletMovement) public movements;
    mapping(string => bool) public usedStateIds;

    event WalletStateRegistered(
        string indexed movementId,
        string userRef,
        string previousStateId,
        string newStateId,
        bytes32 payloadHash,
        bytes32 signatureHash,
        uint256 createdAt
    );

    modifier onlyOwner() {
        require(msg.sender == owner, "ONLY_OWNER");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function registerWalletMovement(
        string calldata userRef,
        string calldata previousStateId,
        string calldata newStateId,
        string calldata movementId,
        bytes32 payloadHash,
        bytes32 signatureHash
    ) external onlyOwner {
        require(bytes(movementId).length > 0, "MOVEMENT_REQUIRED");
        require(bytes(newStateId).length > 0, "STATE_REQUIRED");
        require(!usedStateIds[newStateId], "STATE_ALREADY_USED");
        require(movements[movementId].createdAt == 0, "MOVEMENT_EXISTS");

        WalletMovement memory movement = WalletMovement({
            userRef: userRef,
            previousStateId: previousStateId,
            newStateId: newStateId,
            movementId: movementId,
            payloadHash: payloadHash,
            signatureHash: signatureHash,
            createdAt: block.timestamp
        });

        movements[movementId] = movement;
        usedStateIds[newStateId] = true;
        totalMovements += 1;

        emit WalletStateRegistered(
            movementId,
            userRef,
            previousStateId,
            newStateId,
            payloadHash,
            signatureHash,
            block.timestamp
        );
    }
}

